                templateCode: """
class Solution {
    func isValid(_ s: String) -> Bool {
        return false
    }
}
""",
                solutionCode: """
class Solution {
    func isValid(_ s: String) -> Bool {
        var stack = [Character]()
        let matching: [Character: Character] = [")": "(", "}": "{", "]": "["]
        for char in s {
            if let openBracket = matching[char] {
                if stack.isEmpty || stack.removeLast() != openBracket {
                    return false
                }
            } else {
                stack.append(char)
            }
        }
        return stack.isEmpty
    }
}
""",
