""",
                solutionCode: """
class Solution {
    func leftMostColumnWithOne(_ matrix: [[Int]]) -> Int {
        guard !matrix.isEmpty, !matrix[0].isEmpty else { return -1 }
        let rows = matrix.count
        let cols = matrix[0].count
        var row = 0
        var col = cols - 1
        var result = -1
        while row < rows && col >= 0 {
            if matrix[row][col] == 1 {
                result = col
                col -= 1
            } else {
                row += 1
            }
        }
        return result
    }
}
""",
