class Solution {
    func groupAnagrams(_ strs: [String]) -> [[String]] {
        var map : [String : [String]] = [:]
        for str in strs {
            var key = String(str.sorted())
            print(key)
            if var val = map[key] {
                // print(val)
                val.append(str)
                map[key] = val
            }else{
                map[key] = [str]
            }
            // print(map)
        }
        var ans: [[String]] = []
        for (key, value) in map {
            ans.append(value)
        }
        return ans
    }
}
""",
