""",
                solutionCode: """
class Solution {
    func lengthOfLongestSubstring(_ s: String) -> Int {
        var lastSeen: [Character: Int] = [:]
        var start = 0
        var maxLen = 0
        let chars = Array(s)
        for i in 0..<chars.count {
            if let seenIndex = lastSeen[chars[i]], seenIndex >= start {
                start = seenIndex + 1
            }
            lastSeen[chars[i]] = i
            maxLen = max(maxLen, i - start + 1)
        }
        return maxLen
    }
}
""",
