""",
                solutionCode: """
class Solution {
    func setZeroes(_ matrix: inout [[Int]]) {
        var row0 = false
        var col0 = false
        for j in 0..<matrix[0].count {
            if matrix[0][j] == 0 {
                row0  = true
                break
            }
        }
        for i in 0..<matrix.count {
            if matrix[i][0] == 0 {
                col0 = true
                break
            }
        }
        for i in 1..<matrix.count {
            var found0InRow = false
            for j in 1..<matrix[0].count{
                if matrix[i][j] == 0 {
                    found0InRow = true
                    break
                }
            }
            if found0InRow {
                matrix[i][0] = 0
            }
        }
        for j in 1..<matrix[0].count {
            var found0InCol = false
            for i in 1..<matrix.count {
                if matrix[i][j] == 0 {
                    found0InCol = true
                    break
                }
            }
            if found0InCol {
                matrix[0][j] = 0
            }
        }
        for i in 1..<matrix.count {
            for j in 1..<matrix[0].count {
                if matrix[0][j] == 0 || matrix[i][0] == 0 {
                    matrix[i][j] = 0
                }
            }
        }
        if row0 {
            for j in 0..<matrix[0].count{
                matrix[0][j] = 0
            }
        }
        if col0 {
            for i in 0..<matrix.count{
                matrix[i][0] = 0
            }
        }
    }
}
""",
