                solutionCode: """
class BinaryMatrix {
    private let matrix: [[Int]]
    private(set) var getCallCount = 0

    init(_ matrix: [[Int]]) {
        self.matrix = matrix
    }

    func dimensions() -> [Int] {
        return [matrix.count, matrix.isEmpty ? 0 : matrix[0].count]
    }

    func get(_ x: Int, _ y: Int) -> Int {
        getCallCount += 1
        return matrix[x][y]
    }
}

class Solution {
    func leftMostColumnWithOne(_ binaryMatrix: BinaryMatrix) -> Int {
        let dims = binaryMatrix.dimensions()
        let rows = dims[0]
        let cols = dims[1]

        var row = 0
        var col = cols - 1
        var foundOne = false

        while row < rows && col >= 0 {
            if binaryMatrix.get(row, col) == 1 {
                col -= 1
                foundOne = true
            } else {
                row += 1
            }
        }

        return foundOne ? col + 1 : -1
    }
}
""",
