class Solution {
    func maxSubArray(_ nums: [Int]) -> Int {
        var sum = 0
        var ans = Int.min
        for num in nums {
            if sum < 0 { // compare first
                sum = 0
            }
            sum += num
            ans = max(sum ,ans)
        }

        return ans
    }
}
