    TestCase(ops: [.size, .add("k1", "v59"), .add("k6", "v91"), .add("k2", "v72"), .get("k1"), .size, .get("k1"), .size], expected: ["0", "added", "added", "added", "v59", "3", "v59", "3"], name: "Random Case 4 (n=8)")
